function StatusBadge({ status }: { status: string }) {
  const cfg: Record<string, { label: string; bg: string; color: string }> = {
    active:   { label: "Activo",   bg: "#dcfce7", color: "#16a34a" },
    inactive: { label: "Inactivo", bg: "#fee2e2", color: "#dc2626" },
    failed:   { label: "Fallido",  bg: "#fee2e2", color: "#dc2626" },
  };
  const c = cfg[status] ?? cfg["inactive"];
  return (
    <span className="text-[10px] font-bold px-2 py-0.5 rounded-full" style={{ background: c.bg, color: c.color }}>
      {c.label}
    </span>
  );
}

function LogLine({ line }: { line: typeof LOG_LINES[0] }) {
  const levelColor: Record<string, string> = {
    INFO: "#22c55e", WARN: "#f59e0b", ERROR: "#ef4444", DEBUG: "#64748b",
  };
  return (
    <div className="flex items-start gap-3 py-1 px-3 hover:bg-slate-800/30 rounded text-[11px] font-mono">
      <span style={{ color: "#64748b", flexShrink: 0 }}>{line.ts}</span>
      <span className="w-12 text-center font-bold flex-shrink-0" style={{ color: levelColor[line.level] ?? "#94a3b8" }}>{line.level}</span>
      <span className="w-24 flex-shrink-0" style={{ color: "#94a3b8" }}>{line.src}</span>
      <span style={{ color: "#e2e8f0" }}>{line.msg}</span>
    </div>
  );
}

/* ── Main component ──────────────────────────────────────────── */

export default function SystemMonitor() {
  const [tab, setTab] = useState<Tab>("overview");
  const [diagRunning, setDiagRunning] = useState(false);
  const [diagDone, setDiagDone] = useState(false);
  const [healthRunning, setHealthRunning] = useState(false);
  const [healthDone, setHealthDone] = useState(false);
  const [logFilter, setLogFilter] = useState<"ALL" | "INFO" | "WARN" | "ERROR">("ALL");
  const [metrics, setMetrics] = useState({ cpu: 23, ram: 68, disk: 74, net: 142 });
  const logsRef = useRef<HTMLDivElement>(null);

  /* simulate live metric fluctuation */
  useEffect(() => {
    const id = setInterval(() => {
      setMetrics((m) => ({
        cpu:  Math.min(95, Math.max(5,  m.cpu  + (Math.random() - 0.5) * 6)),
        ram:  Math.min(95, Math.max(40, m.ram  + (Math.random() - 0.5) * 2)),
        disk: m.disk,
        net:  Math.min(500, Math.max(20, m.net + (Math.random() - 0.5) * 30)),
      }));
    }, 2500);
    return () => clearInterval(id);
  }, []);

  const runDiag = useCallback(() => {
    setDiagRunning(true);
    setDiagDone(false);
    setTimeout(() => { setDiagRunning(false); setDiagDone(true); }, 2200);
  }, []);

  const runHealth = useCallback(() => {
    setHealthRunning(true);
    setHealthDone(false);
    setTimeout(() => { setHealthRunning(false); setHealthDone(true); }, 1800);
  }, []);

  const filteredLogs = logFilter === "ALL" ? LOG_LINES : LOG_LINES.filter((l) => l.level === logFilter);

  const tabs: { id: Tab; label: string; icon: string }[] = [
    { id: "overview",    label: "Vista General",  icon: "ti-layout-dashboard" },
    { id: "diagnostics", label: "Diagnósticos",   icon: "ti-shield-check" },
    { id: "health",      label: "Vitalidad",      icon: "ti-heartbeat" },
    { id: "logs",        label: "Consola de Logs", icon: "ti-terminal-2" },
    { id: "alerts",      label: "Alertas",        icon: "ti-bell" },
  ];

  const alertCount = ALERTS.filter((a) => a.sev === "critical" || a.sev === "warn").length;

  return (
    <div className="flex flex-col h-full overflow-hidden bg-slate-50 dark:bg-darkbg">

      {/* Header */}
      <div className="flex-shrink-0 bg-white dark:bg-darkcard border-b border-slate-200 dark:border-darkborder px-6 pt-4 pb-0">
        <div className="flex items-center justify-between mb-1">
          <div className="flex items-center gap-2">
            <div className="w-7 h-7 rounded-lg bg-emerald-50 dark:bg-emerald-950/30 flex items-center justify-center">
              <i className="ti ti-server text-sm text-emerald-500" />
            </div>
            <h1 className="text-base font-bold text-slate-900 dark:text-white">Monitor del Sistema</h1>
            <span className="text-[10px] font-bold uppercase tracking-widest px-2 py-0.5 rounded-full bg-emerald-50 text-emerald-600 border border-emerald-200 dark:bg-emerald-900/20 dark:text-emerald-400 dark:border-emerald-800">
              Admin OS v1.0
            </span>
          </div>
          <div className="flex items-center gap-2 text-xs px-3 py-1.5 rounded-xl bg-emerald-50 border border-emerald-200 text-emerald-600 dark:bg-emerald-950/30 dark:border-emerald-800 dark:text-emerald-400">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75" />
              <span className="relative inline-flex rounded-full h-2 w-2 bg-emerald-500" />
            </span>
            <span className="font-semibold">Servidor Conectado</span>
          </div>
        </div>
        <p className="text-xs text-slate-400 mb-3">ubuntu-server-prod · Consola Central de Servidores &amp; Servicios</p>

        {/* Tabs */}
        <div className="flex gap-0.5">
          {tabs.map((t) => (
            <button
              key={t.id}
              onClick={() => setTab(t.id)}
              className="relative flex items-center gap-1.5 px-4 py-2 text-xs font-semibold rounded-t-lg transition-all border border-b-0"
              style={
                tab === t.id
                  ? { background: "#f8fafc", borderColor: "#e2e8f0", color: "#059669" }
                  : { background: "transparent", borderColor: "transparent", color: "#94a3b8" }
              }
            >
              <i className={`ti ${t.icon} text-sm`} />
              {t.label}
              {t.id === "alerts" && alertCount > 0 && (
                <span className="ml-1 text-[9px] font-bold px-1.5 py-0.5 rounded-full bg-amber-100 text-amber-700 border border-amber-200">
                  {alertCount}
                </span>
              )}
            </button>
          ))}
        </div>
      </div>

      {/* Body */}
      <div className="flex-1 overflow-y-auto p-6">

        {/* ── OVERVIEW ── */}
        {tab === "overview" && (
          <div className="space-y-6">
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
              <MetricCard label="CPU" value={`${metrics.cpu.toFixed(0)}%`} sub="8 vCPUs · Intel Xeon E5" icon="ti-cpu" color="#3b6fed" percent={metrics.cpu} />
              <MetricCard label="Memoria RAM" value={`${metrics.ram.toFixed(0)}%`} sub="10.8 GB libres de 16 GB" icon="ti-device-desktop-analytics" color="#f59e0b" percent={metrics.ram} />
              <MetricCard label="Almacenamiento" value={`${metrics.disk}%`} sub="12.5 GB libres de SSD" icon="ti-device-floppy" color="#ef4444" percent={metrics.disk} />
              <MetricCard label="Red" value={`${metrics.net.toFixed(0)} KB/s`} sub="↑ 38 KB/s · ↓ rest" icon="ti-wifi" color="#10b981" />
            </div>

            {/* Services */}
            <div className="bg-white dark:bg-darkcard rounded-2xl border border-slate-100 dark:border-darkborder p-5">
              <div className="flex items-center justify-between mb-4">
                <div>
                  <h3 className="text-sm font-bold text-slate-900 dark:text-white">Servicios del Sistema (Systemd)</h3>
                  <p className="text-xs text-slate-400">Verifica, monitorea y controla los procesos del servidor</p>
                </div>
                <span className="text-xs font-semibold bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 px-3 py-1 rounded-lg">
                  {SERVICES.filter((s) => s.status === "active").length} Activos
                </span>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-xs">
                  <thead>
                    <tr className="border-b border-slate-100 dark:border-darkborder">
                      {["Servicio", "Estado", "PID", "Uptime", "CPU", "Mem"].map((h) => (
                        <th key={h} className="text-left pb-2 pr-4 font-semibold text-slate-400 uppercase tracking-wider text-[10px]">{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50 dark:divide-darkborder">
                    {SERVICES.map((s) => (
                      <tr key={s.name} className="hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-colors">
                        <td className="py-2.5 pr-4 font-mono font-semibold text-slate-800 dark:text-slate-200">{s.name}</td>
                        <td className="py-2.5 pr-4"><StatusBadge status={s.status} /></td>
                        <td className="py-2.5 pr-4 font-mono text-slate-500">{s.pid}</td>
                        <td className="py-2.5 pr-4 text-slate-500">{s.uptime}</td>
                        <td className="py-2.5 pr-4 text-slate-500">{s.cpu}</td>
                        <td className="py-2.5 text-slate-500">{s.mem}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {/* Ports */}
            <div className="bg-white dark:bg-darkcard rounded-2xl border border-slate-100 dark:border-darkborder p-5">
              <h3 className="text-sm font-bold text-slate-900 dark:text-white mb-1">Puertos Activos en Escucha</h3>
              <p className="text-xs text-slate-400 mb-4">Puertos TCP en estado LISTEN</p>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                {PORTS.map((p) => (
                  <div key={p.port} className="flex items-center gap-3 p-3 rounded-xl border border-slate-100 dark:border-darkborder">
                    <span className="text-lg font-black font-mono text-slate-200 dark:text-slate-700">:{p.port}</span>
                    <div className="flex-1 min-w-0">
                      <p className="text-xs font-semibold text-slate-800 dark:text-slate-200 truncate">{p.service}</p>
                      <p className="text-[10px] text-slate-400">{p.proto} · {p.status}</p>
                    </div>
                    <span className="w-2 h-2 rounded-full bg-emerald-400 flex-shrink-0" />
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* ── DIAGNOSTICS ── */}
        {tab === "diagnostics" && (
          <div className="space-y-5">
            <div className="bg-white dark:bg-darkcard rounded-2xl border border-slate-100 dark:border-darkborder p-6">
              <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-5">
                <div>
                  <h3 className="text-sm font-bold text-slate-900 dark:text-white">Diagnóstico Integral de Clientum</h3>
                  <p className="text-xs text-slate-400 font-mono">scripts-ubuntu/monitoreo/diagnostico.sh</p>
                </div>
                <button
                  onClick={runDiag}
                  disabled={diagRunning}
                  className="flex items-center gap-2 px-5 py-2.5 text-xs font-bold rounded-xl text-white transition-all disabled:opacity-60"
                  style={{ background: "#059669" }}
                >
                  {diagRunning ? <><i className="ti ti-loader-2 animate-spin text-sm" /> Ejecutando…</> : "Ejecutar Auditoría Completa"}
                </button>
              </div>

              <div className="border border-slate-200 dark:border-darkborder rounded-xl overflow-hidden">
                <div className="bg-slate-50 dark:bg-slate-800/50 px-4 py-2 border-b border-slate-200 dark:border-darkborder flex justify-between items-center text-[10px] font-semibold text-slate-400 uppercase tracking-wider">
                  <span>Reporte de Auditoría</span>
                  <span className="font-mono">{diagDone ? new Date().toLocaleTimeString("es-AR") : "–"}</span>
                </div>
                <div className="p-4 min-h-[240px]">
                  {!diagDone && !diagRunning && (
                    <p className="text-slate-400 text-sm text-center pt-12">Haga clic en "Ejecutar Auditoría Completa" para auditar el sistema.</p>
                  )}
                  {diagRunning && (
                    <div className="flex flex-col gap-2">
                      {["Verificando variables de entorno…", "Conectando a PostgreSQL…", "Revisando builds y dependencias…", "Validando certificados AFIP…", "Auditando backups…"].map((l, i) => (
                        <div key={i} className="flex items-center gap-2 text-xs font-mono" style={{ color: "#94a3b8", animationDelay: `${i * 0.3}s` }}>
                          <i className="ti ti-loader-2 animate-spin text-sm text-emerald-400" />
                          {l}
                        </div>
                      ))}
                    </div>
                  )}
                  {diagDone && (
                    <div className="space-y-2">
                      {DIAG_RESULTS.map((r) => (
                        <div key={r.category} className="flex items-start gap-3 p-3 rounded-lg" style={{ background: r.status === "ok" ? "#f0fdf4" : "#fffbeb" }}>
                          <i
                            className={`ti ${r.status === "ok" ? "ti-circle-check" : "ti-alert-triangle"} text-sm mt-0.5`}
                            style={{ color: r.status === "ok" ? "#16a34a" : "#d97706" }}
                          />
                          <div>
                            <p className="text-xs font-bold" style={{ color: r.status === "ok" ? "#15803d" : "#92400e" }}>{r.category}</p>
                            <p className="text-[11px]" style={{ color: r.status === "ok" ? "#166534" : "#92400e" }}>{r.msg}</p>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* ── HEALTH ── */}
        {tab === "health" && (
          <div className="space-y-5">
            <div className="bg-white dark:bg-darkcard rounded-2xl border border-slate-100 dark:border-darkborder p-6">
              <div className="flex items-center justify-between mb-5">
                <div>
                  <h3 className="text-sm font-bold text-slate-900 dark:text-white">Health Check de Vitalidad</h3>
                  <p className="text-xs text-slate-400 font-mono">scripts-ubuntu/monitoreo/health-check.sh</p>
                </div>
                <button
                  onClick={runHealth}
                  disabled={healthRunning}
                  className="flex items-center gap-2 px-5 py-2.5 text-xs font-bold rounded-xl text-white transition-all disabled:opacity-60"
                  style={{ background: "#059669" }}
                >
                  {healthRunning ? <><i className="ti ti-loader-2 animate-spin text-sm" /> Verificando…</> : "Ejecutar Test"}
                </button>
              </div>

              {!healthDone && !healthRunning && (
                <p className="text-slate-400 text-sm text-center py-10">Haga clic en "Ejecutar Test" para verificar el estado de todos los servicios.</p>
              )}

              {healthRunning && (
                <div className="space-y-2">
                  {HEALTH_CHECKS.slice(0, 4).map((h) => (
                    <div key={h.name} className="flex items-center gap-3 p-3 rounded-xl border border-slate-100 dark:border-darkborder animate-pulse">
                      <i className="ti ti-loader-2 animate-spin text-sm text-slate-400" />
                      <span className="text-xs text-slate-500">{h.name}</span>
                    </div>
                  ))}
                </div>
              )}

              {healthDone && (
                <div className="space-y-2">
                  {HEALTH_CHECKS.map((h) => (
                    <div
                      key={h.name}
                      className="flex items-center gap-3 p-3 rounded-xl border"
                      style={{ borderColor: h.status === "ok" ? "#dcfce7" : "#fef3c7", background: h.status === "ok" ? "#f0fdf4" : "#fffbeb" }}
                    >
                      <i
                        className={`ti ${h.status === "ok" ? "ti-check" : "ti-alert-triangle"} text-sm`}
                        style={{ color: h.status === "ok" ? "#16a34a" : "#d97706" }}
                      />
                      <div className="flex-1 min-w-0">
                        <p className="text-xs font-semibold" style={{ color: h.status === "ok" ? "#15803d" : "#92400e" }}>{h.name}</p>
                        <p className="text-[10px] font-mono" style={{ color: "#94a3b8" }}>{h.endpoint}</p>
                      </div>
                      <div className="text-right flex-shrink-0">
                        {h.code && <span className="text-[10px] font-mono text-slate-400">{h.code}</span>}
                        <p className="text-[10px] font-mono" style={{ color: "#64748b" }}>{h.latency}</p>
                      </div>
                    </div>
                  ))}
                  <div className="flex items-center gap-3 pt-3 text-xs text-slate-500">
                    <i className="ti ti-check text-emerald-500" />
                    {HEALTH_CHECKS.filter((h) => h.status === "ok").length} / {HEALTH_CHECKS.length} checks pasaron
                    {HEALTH_CHECKS.some((h) => h.status !== "ok") && (
                      <span className="text-amber-600 font-semibold">· {HEALTH_CHECKS.filter((h) => h.status !== "ok").length} advertencia(s)</span>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {/* ── LOGS ── */}
        {tab === "logs" && (
          <div className="h-full">
            <div className="bg-slate-900 rounded-2xl border border-slate-700 overflow-hidden" style={{ minHeight: "400px" }}>
              <div className="flex items-center justify-between px-4 py-2.5 border-b border-slate-700 bg-slate-800">
                <div className="flex items-center gap-2">
                  <i className="ti ti-terminal-2 text-sm text-emerald-400" />
                  <span className="text-xs font-semibold text-slate-300">Consola de Logs — Tiempo Real</span>
                </div>
                <div className="flex items-center gap-1">
                  {(["ALL", "INFO", "WARN", "ERROR"] as const).map((f) => (
                    <button
                      key={f}
                      onClick={() => setLogFilter(f)}
                      className="px-2 py-0.5 text-[10px] font-bold rounded transition-all"
                      style={
                        logFilter === f
                          ? { background: f === "ERROR" ? "#ef4444" : f === "WARN" ? "#f59e0b" : "#22c55e", color: "#fff" }
                          : { background: "rgba(255,255,255,0.05)", color: "#64748b" }
                      }
                    >
                      {f}
                    </button>
                  ))}
                </div>
              </div>
              <div ref={logsRef} className="p-3 overflow-y-auto" style={{ maxHeight: "500px" }}>
                {filteredLogs.map((line, i) => (
                  <LogLine key={i} line={line} />
                ))}
              </div>
            </div>
          </div>
        )}

        {/* ── ALERTS ── */}
        {tab === "alerts" && (
          <div className="space-y-4">
            <div className="flex items-center gap-3 text-xs text-slate-500">
              <i className="ti ti-bell text-sm" />
              {ALERTS.length} alertas activas · {ALERTS.filter((a) => a.sev === "critical").length} críticas
            </div>
            {ALERTS.map((a, i) => {
              const sevCfg: Record<string, { border: string; bg: string; color: string; label: string }> = {
                critical: { border: "#ef4444", bg: "#fff1f2", color: "#dc2626", label: "Crítico" },
                warn:     { border: "#f59e0b", bg: "#fffbeb", color: "#d97706", label: "Advertencia" },
                info:     { border: "#3b82f6", bg: "#eff6ff", color: "#2563eb", label: "Info" },
              };
              const s = sevCfg[a.sev] ?? sevCfg["info"];
              return (
                <div key={i} className="flex items-start gap-4 p-5 rounded-2xl border" style={{ background: s.bg, borderColor: `${s.border}40` }}>
                  <div className="w-9 h-9 rounded-xl flex items-center justify-center flex-shrink-0" style={{ background: `${s.border}15` }}>
                    <i className={`ti ${a.icon} text-sm`} style={{ color: s.color }} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <h4 className="text-sm font-bold" style={{ color: "#0f172a" }}>{a.title}</h4>
                      <span className="text-[10px] font-bold px-2 py-0.5 rounded-full" style={{ background: `${s.border}20`, color: s.color }}>{s.label}</span>
                    </div>
                    <p className="text-xs" style={{ color: "#64748b" }}>{a.desc}</p>
                    <p className="text-[10px] mt-1 font-mono" style={{ color: "#94a3b8" }}>{a.time}</p>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

